// paginationClass generates CSS class for pagination container.
func paginationClass(class string) string {
	if class == "" {
		return "pagination"
	}
	var b strings.Builder
	b.Grow(25)
	b.WriteString("pagination ")
	b.WriteString(class)
	return b.String()
}

var _ = templruntime.GeneratedTemplate
